  function makeDraggable($element, $handle) {
    $handle.addClass("gal-draggable-handle");
    let isDragging = false;
    let startX2, startY2, initialLeft, initialTop;
    $handle.on("mousedown touchstart", function(e) {
      if ($2(e.target).closest("button, input, a, .gal-config-close, .close").length) return;
      e.preventDefault();
      isDragging = true;
      const evt = e.type === "touchstart" ? e.touches[0] : e;
      startX2 = evt.clientX;
      startY2 = evt.clientY;
      const offset = $element.offset();
      initialLeft = offset.left;
      initialTop = offset.top;
      $element.css({
        position: "fixed",
        margin: 0,
        left: initialLeft - $2(topWindow).scrollLeft(),
        top: initialTop - $2(topWindow).scrollTop(),
        transform: "none"
      });
    });
    $2(topWindow).on("mousemove touchmove", function(e) {
      if (!isDragging) return;
      e.preventDefault();
      const evt = e.type === "touchmove" ? e.touches[0] : e;
      const dx = evt.clientX - startX2;
      const dy = evt.clientY - startY2;
      $element.css({
        left: initialLeft - $2(topWindow).scrollLeft() + dx,
        top: initialTop - $2(topWindow).scrollTop() + dy
      });
    });
    $2(topWindow).on("mouseup touchend", function() {
      isDragging = false;
    });
  }

